mapper.sql:
FROM clinical_event ce
INNER JOIN patient p ON ce.patient_id = p.internal_id
INNER JOIN cancer_study cs ON p.cancer_study_id = cs.cancer_study_id
WHERE cs.cancer_study_identifier = #{studyId}
  AND p.stable_id = #{patientId}

mapper.select:
SELECT ce.clinical_event_id AS clinicalEventId, ce.event_type AS eventType, p.stable_id AS patientId, cs.cancer_study_identifier AS studyId
ORDER BY ce.clinical_event_id ASC
LIMIT #{limit} OFFSET #{offset}
